import{_ as i}from"./chunks/demo-main.zRXlsRu9.js";import{c as a,Q as d,j as t,m as r}from"./chunks/framework.BkjtU8k0.js";const m=JSON.parse('{"title":"Flyfish Viewer","titleTemplate":false,"description":"","frontmatter":{"layout":"home","title":"Flyfish Viewer","titleTemplate":false,"hero":{"name":"Flyfish Viewer","text":"纯前端多格式文件预览组件","tagline":"官方文档、组件主页和交付说明都在这里。Flyfish Viewer 提供 Vue3 与 Vue2.7 两条 npm 包线，把 Word、Excel、PPT、PDF、OFD、CAD、Markdown、代码、图片和视频预览能力放进浏览器端完成。","image":{"src":"/_media/logo.svg","alt":"Flyfish Viewer"},"actions":[{"theme":"brand","text":"快速开始","link":"/guide/quickstart"},{"theme":"alt","text":"在线 Demo","link":"https://viewer.flyfish.dev"},{"theme":"alt","text":"GitHub 成品仓库","link":"https://github.com/flyfish-dev/file-viewer"},{"theme":"alt","text":"npm(Vue3)","link":"https://www.npmjs.com/package/@flyfish-group/file-viewer3"},{"theme":"alt","text":"npm(Vue2)","link":"https://www.npmjs.com/package/@flyfish-group/file-viewer"}]},"features":[{"title":"纯前端 Serverless","details":"不依赖后端转码服务，浏览器直接完成解析和渲染，适合静态部署、私有化部署和离线场景。"},{"title":"59 种扩展名覆盖","details":"覆盖 Office、PDF、OFD、CAD、Markdown、代码/文本、图片和视频，完整承接常见附件中心需求。"},{"title":"按需异步加载","details":"OFD、CAD、PDF、Office、Markdown 和代码高亮链路按格式拆包，重型依赖不拖慢其他文件首屏。"},{"title":"真实文档阅读体验","details":"PDF 和 Word 视图保留灰色工作台、白色纸张、页面导航、自适应缩放和长文档滚动体验。"},{"title":"双 Vue 包与 iframe","details":"Vue3 使用 @flyfish-group/file-viewer3，Vue2.7 使用 @flyfish-group/file-viewer，多系统复用时也可以通过 iframe 嵌入。"},{"title":"面向交付","details":"README、文档站、Demo、混淆压缩、npm tarball 和公开成品仓库一起维护，拿到即可验收和分发。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1779171725000}'),s={name:"index.md"};function l(o,e,c,f,h,p){return d(),t("div",null,[...e[0]||(e[0]=[r('<div class="doc-kicker">Official Docs And Component Home</div><p class="doc-lead"> 这个站点同时承担 Flyfish Viewer 的组件主页、官方文档和成品交付说明。 你可以先从这里判断它是否适合你的业务，再进入快速开始、组件用法、iframe 嵌入、支持格式和发布分发章节。 </p><div class="doc-link-row"><a href="/guide/">文档导览</a><a href="/guide/formats">支持格式</a><a href="/guide/usage">组件用法</a><a href="/guide/iframe">Iframe 嵌入</a><a href="/guide/distribution">成品分发</a></div><div class="doc-shot"><img src="'+i+'" alt="Flyfish Viewer 主界面预览"><p class="doc-caption">在线 Demo 集成完整样例文件选择器、上传入口和多格式预览区，可直接用于验收真实浏览体验。</p></div><h2 id="优势一览" tabindex="-1">优势一览 <a class="header-anchor" href="#优势一览" aria-label="Permalink to &quot;优势一览&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>少一条服务端链路</h3><p>大多数格式直接在浏览器完成解析，不需要把附件交给后端转 PDF，也减少了临时文件、任务队列和清理脚本的维护成本。</p></div><div class="doc-card"><h3>格式覆盖更贴近业务</h3><p>除了 Office、PDF 和图片，也补齐 OFD、DXF、Markdown、代码、日志、配置文件和 MP4，适合 OA、知识库、工单和附件中心。</p></div><div class="doc-card"><h3>重型能力不抢首屏</h3><p>PDF、OFD、CAD、Office 和代码高亮都按需异步加载。用户打开图片或文本时，不会因为图纸或版式文档解析器而额外等待。</p></div><div class="doc-card"><h3>阅读质感有兜底</h3><p>Word 保留白色纸张和灰色页面底，PDF 具备缩放、页码、导航窗格和宽度自适应，长文档打开后默认就应该可读。</p></div><div class="doc-card"><h3>接入边界清晰</h3><p>Vue3 与 Vue2.7 都有对应 npm 包，iframe 方案适合多系统复用。URL、File、Blob 转 File 等输入路径在文档里都有示例。</p></div><div class="doc-card"><h3>成品可直接下载</h3><p>公开仓库提供混淆压缩库产物、Demo 静态站点、文档静态站点、样例文件和 tarball，源码需求可通过官方渠道自助开通。</p></div></div><h2 id="最快接入路径" tabindex="-1">最快接入路径 <a class="header-anchor" href="#最快接入路径" aria-label="Permalink to &quot;最快接入路径&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>我想先看效果</h3><p>打开 <a href="https://viewer.flyfish.dev" target="_blank" rel="noreferrer">在线 Demo</a>，用内置样例或本地文件验证格式、缩放、导航和样式表现。</p></div><div class="doc-card"><h3>我在 Vue 3 项目里用</h3><p>安装 <code>@flyfish-group/file-viewer3@1.0.7</code>，再查看 <a href="/guide/quickstart-vue3">Vue3 集成</a> 接入 URL 或 File 输入。</p></div><div class="doc-card"><h3>我还在 Vue2 项目里用</h3><p>安装 <code>@flyfish-group/file-viewer@1.0.7</code>，按 <a href="/guide/quickstart-vue2">Vue2 集成</a> 使用 <code>Vue.use(FileViewer)</code> 注册。</p></div><div class="doc-card"><h3>我要给多个系统共用</h3><p>阅读 <a href="/guide/iframe">Iframe 嵌入</a>，把预览器作为独立静态站部署，通过 URL 或 postMessage 推送二进制文件。</p></div><div class="doc-card"><h3>我要下载成品或二开</h3><p>查看 <a href="/guide/distribution">发布与成品分发</a>。公开仓库提供可下载产物，源码和商业二开通过官方渠道开通。</p></div></div><div class="doc-callout"><strong>官方入口:</strong> 文档站是 <a href="https://doc.flyfish.dev">doc.flyfish.dev</a>，在线预览是 <a href="https://viewer.flyfish.dev">viewer.flyfish.dev</a>，公开成品仓库是 <a href="https://github.com/flyfish-dev/file-viewer">github.com/flyfish-dev/file-viewer</a>。 </div>',9)])])}const u=a(s,[["render",l]]);export{m as __pageData,u as default};
